1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  Pressable,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	  type StyleProp,
