78	  return (
79	    <View style={styles.segmentRow} accessibilityRole="tablist">
80	      {SEGMENTS.map((s) => (
81	        <SegmentButton
82	          key={s.key}
83	          label={s.label}
84	          selected={active === s.key}
85	          onPress={() => onChange(s.key)}
86	          testID={`segment-${s.key}`}
87	        />
88	      ))}
89	    </View>
90	  );
91	}
92	
93	type SegmentButtonProps = {
94	  label: string;
95	  selected: boolean;
96	  onPress: () => void;
97	  testID?: string;
98	};
99	
100	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
101	  const bg = selected ? colors.primarySoft : colors.surface;
102	  const textColor = selected ? colors.primaryDeep : colors.ink;
103	  return (
104	    <Pressable
105	      onPress={onPress}
106	      accessibilityRole="tab"
107	      accessibilityState={{ selected }}
108	      accessibilityLabel={label}
109	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
110	      testID={testID}
111	    >
112	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
113	        {label}
114	      </Text>
115	    </Pressable>
116	  );
117	}
