119	export default function Applications() {
120	  const { user } = useAuth();
121	  const userId = user?.id ?? null;
122	  const { show: showToast } = useToast();
123	
124	  const [segment, setSegment] = useState<Segment>('pending');
125	  const [rows, setRows] = useState<ApplicationRow[]>([]);
126	  const [loading, setLoading] = useState(true);
127	  const [error, setError] = useState<string | null>(null);
128	
129	  // Realtime handler reads the prior status to detect real transitions
130	  // (no-op UPDATEs shouldn't trigger a toast). A ref mirrors `rows` so the
131	  // subscription callback sees the latest state without re-subscribing on
132	  // every list mutation.
133	  const rowsRef = useRef<ApplicationRow[]>([]);
134	  useEffect(() => {
135	    rowsRef.current = rows;
136	  }, [rows]);
137	
138	  const load = useCallback(async () => {
139	    if (!userId) return;
140	    setLoading(true);
141	    setError(null);
142	    const { data, error: rpcError } = await supabase.rpc('list_my_applications');
143	    if (rpcError) {
144	      setError("Couldn't load applications.");
145	      setRows([]);
146	    } else {
147	      setRows(data ?? []);
148	    }
149	    setLoading(false);
150	  }, [userId]);
151	
152	  useEffect(() => {
153	    void load();
154	  }, [load]);
155	
156	  // US-044 — Subscribe to UPDATE events on the caller's own applications.
157	  // RLS (`applications_creator_rw`) enforces the security boundary; the
158	  // `creator_id=eq.<id>` filter is a client-side throughput guard so the
159	  // Realtime broker doesn't ship rows we'll discard. We use
160	  // `supabase.realtime.setAuth(token)` for the same reason as the US-036
161	  // pattern (Codebase Pattern #105) — websocket auth doesn't go through
162	  // the marketifyFetch Authorization wrapper.
163	  useEffect(() => {
164	    if (!userId) return;
165	    const token = getCachedToken();
166	    if (!token) return;
167	    let cancelled = false;
168	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
169	    void supabase.realtime.setAuth(token).then(() => {
170	      if (cancelled) return;
171	      activeChannel = supabase
172	        .channel(`creator-applications-${userId}`)
173	        .on(
174	          'postgres_changes',
175	          {
176	            event: 'UPDATE',
177	            schema: 'public',
178	            table: 'applications',
179	            filter: `creator_id=eq.${userId}`,
180	          },
181	          (payload) => {
182	            const next = payload.new as { id?: string; status?: ApplicationStatus };
183	            if (!next.id || !next.status) return;
184	            const prior = rowsRef.current.find((r) => r.id === next.id);
185	            if (!prior) return;
186	            if (prior.status === next.status) return;
187	            const nextStatus = next.status;
188	            setRows((cur) =>
189	              cur.map((r) => (r.id === next.id ? { ...r, status: nextStatus } : r)),
190	            );
191	            if (nextStatus === 'approved') {
192	              showToast({
193	                message: 'Your application was approved',
194	                variant: 'success',
195	              });
196	            } else if (nextStatus === 'rejected') {
197	              showToast({
198	                message: 'Your application was rejected',
199	                variant: 'error',
200	              });
201	            }
202	          },
203	        )
204	        .subscribe();
205	    });
206	    return () => {
207	      cancelled = true;
208	      if (activeChannel) void supabase.removeChannel(activeChannel);
209	    };
210	  }, [userId, showToast]);
211	
212	  const byBucket = useMemo(() => {
213	    const map: Record<Segment, ApplicationRow[]> = {
214	      pending: [],
215	      approved: [],
216	      rejected: [],
217	      cancelled: [],
218	    };
219	    for (const r of rows) {
220	      map[STATUS_BUCKET[r.status]].push(r);
221	    }
222	    return map;
223	  }, [rows]);
224	
225	  const visible = byBucket[segment];
226	
227	  return (
228	    <SafeAreaView style={styles.root}>
229	      <ScrollView contentContainerStyle={styles.scroll}>
230	        <Text style={[textStyles.display, styles.header]}>Applied</Text>
231	        <SegmentControl active={segment} onChange={setSegment} />
232	
233	        {loading ? (
234	          <View style={styles.list} testID="applications-loading">
235	            <SkeletonCard />
236	            <SkeletonCard />
237	          </View>
238	        ) : error ? (
239	          <View style={styles.emptyBox}>
240	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
241	          </View>
242	        ) : visible.length === 0 ? (
243	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
244	            <Text style={[textStyles.body, { color: colors.ink70 }]}>
245	              {emptyMessageFor(segment)}
246	            </Text>
247	          </View>
248	        ) : (
249	          <View style={styles.list}>
250	            {visible.map((row) => (
251	              <ApplicationRowCard key={row.id} row={row} />
252	            ))}
253	          </View>
254	        )}
255	      </ScrollView>
256	    </SafeAreaView>
257	  );
258	}
259	
260	function emptyMessageFor(segment: Segment): string {
261	  switch (segment) {
262	    case 'pending':
263	      return 'No pending applications yet. Apply from Discover.';
264	    case 'approved':
265	      return 'Nothing approved yet — keep applying.';
266	    case 'rejected':
267	      return 'No rejections here.';
268	    case 'cancelled':
269	      return 'No cancelled applications.';
270	  }
271	}
272	
273	type ApplicationRowCardProps = {
274	  row: ApplicationRow;
275	  style?: StyleProp<ViewStyle>;
276	};
277	
278	// Title fallback: prefer listings.title (current), fall back to the
279	// version snapshot title (what the creator originally applied against),
280	// then a generic. Both fields come from the RPC so both are always
281	// populated for rows the caller owns.
282	function resolveTitle(row: ApplicationRow): string {
283	  return row.listing_title || row.version_title || 'Untitled campaign';
284	}
285	
286	function ApplicationRowCard({ row, style }: ApplicationRowCardProps) {
287	  const title = resolveTitle(row);
288	  const handle = row.lister_handle;
289	  const pillStatus: StatusPillStatus = STATUS_BUCKET[row.status];
290	  const relative = formatRelativeTime(new Date(row.created_at));
291	
292	  const onPress = useCallback(() => {
293	    // Approved apps route to the submission composer (US-046); everything
294	    // else still surfaces the listing detail so creators can read the brief.
295	    if (row.status === 'approved') {
296	      router.push(`/(creator)/submit/${row.id}`);
297	    } else {
298	      router.push(`/(creator)/listing/${row.listing_id}`);
299	    }
300	  }, [row.id, row.listing_id, row.status]);
301	
302	  return (
303	    <Pressable
304	      onPress={onPress}
305	      accessibilityRole="button"
306	      accessibilityLabel={`${title}${handle ? ` by @${handle}` : ''}, ${pillStatus}, applied ${relative}`}
307	      style={[styles.card, shadows.hard, style]}
308	      testID={`application-${row.id}`}
309	    >
310	      <View style={styles.cardTopRow}>
311	        <View style={styles.cardTitleBlock}>
312	          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={2}>
313	            {title}
314	          </Text>
315	          {handle ? (
316	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>@{handle}</Text>
317	          ) : null}
318	        </View>
319	        <StatusPill status={pillStatus} />
320	      </View>
321	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
322	    </Pressable>
323	  );
324	}
325	
326	const styles = StyleSheet.create({
327	  root: { flex: 1, backgroundColor: colors.canvas },
328	  scroll: {
329	    padding: spacing.base,
330	    gap: spacing.md,
331	    paddingBottom: spacing.xxxl,
332	  },
